{
  "version": "arkpilot-uitree/v2",
  "kind": "semantic-ui-protocol",
  "appName": "平安扣",
  "appNameEn": "Pinankou",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-header-title",
          "role": "assertion",
          "binding": "/app/title"
        },
        {
          "id": "home-stat-today-inspection",
          "role": "assertion",
          "binding": "/stats/todayInspectionCount"
        },
        {
          "id": "home-stat-pending-risk",
          "role": "assertion",
          "binding": "/stats/pendingRiskCount"
        },
        {
          "id": "home-stat-overdue-risk",
          "role": "assertion",
          "binding": "/stats/overdueRiskCount"
        },
        {
          "id": "home-stat-closed-rate",
          "role": "assertion",
          "binding": "/stats/closedRate"
        },
        {
          "id": "home-quick-action-report",
          "role": "action",
          "event": "navigate-report-risk"
        },
        {
          "id": "home-quick-action-inspection",
          "role": "action",
          "event": "navigate-inspection"
        },
        {
          "id": "home-quick-action-contact",
          "role": "action",
          "event": "navigate-emergency"
        },
        {
          "id": "home-chart-risk-distribution",
          "role": "assertion",
          "binding": "/charts/riskDistribution"
        },
        {
          "id": "home-recent-activity-list",
          "role": "list",
          "binding": "/activities",
          "itemIdPattern": "home-activity-{id}",
          "emptyStateId": "home-empty-activity"
        }
      ]
    },
    {
      "id": "inspection-page",
      "surfaceId": "inspection",
      "pageId": "inspection-page",
      "name": "巡检",
      "route": "pages/Inspection",
      "tabId": "tab-inspection",
      "semanticTargets": [
        {
          "id": "inspection-segment-today",
          "role": "action",
          "event": "switch-segment-today"
        },
        {
          "id": "inspection-segment-pending",
          "role": "action",
          "event": "switch-segment-pending"
        },
        {
          "id": "inspection-segment-history",
          "role": "action",
          "event": "switch-segment-history"
        },
        {
          "id": "inspection-task-list",
          "role": "list",
          "binding": "/inspectionTasks",
          "itemIdPattern": "inspection-task-{id}",
          "emptyStateId": "inspection-empty-task"
        },
        {
          "id": "inspection-task-start-{id}",
          "role": "action",
          "event": "start-inspection",
          "context": { "itemIdPattern": "inspection-task-{id}" }
        },
        {
          "id": "inspection-add-task",
          "role": "action",
          "event": "open-add-inspection-sheet"
        }
      ]
    },
    {
      "id": "inspection-detail-page",
      "surfaceId": "inspection-detail",
      "pageId": "inspection-detail-page",
      "name": "巡检详情",
      "route": "pages/InspectionDetail",
      "semanticTargets": [
        {
          "id": "inspection-detail-title",
          "role": "assertion",
          "binding": "/inspectionDetail/title"
        },
        {
          "id": "inspection-detail-checklist",
          "role": "list",
          "binding": "/inspectionDetail/checkItems",
          "itemIdPattern": "inspection-checkitem-{id}",
          "emptyStateId": "inspection-empty-checkitem"
        },
        {
          "id": "inspection-checkitem-pass-{id}",
          "role": "action",
          "event": "mark-checkitem-pass",
          "context": { "itemIdPattern": "inspection-checkitem-{id}" }
        },
        {
          "id": "inspection-checkitem-fail-{id}",
          "role": "action",
          "event": "mark-checkitem-fail",
          "context": { "itemIdPattern": "inspection-checkitem-{id}" }
        },
        {
          "id": "inspection-checkitem-note-{id}",
          "role": "input",
          "binding": "/inspectionDetail/checkItems/{id}/note"
        },
        {
          "id": "inspection-submit-result",
          "role": "action",
          "event": "submit-inspection-result"
        }
      ]
    },
    {
      "id": "risk-page",
      "surfaceId": "risk",
      "pageId": "risk-page",
      "name": "隐患",
      "route": "pages/Risk",
      "tabId": "tab-risk",
      "semanticTargets": [
        {
          "id": "risk-filter-all",
          "role": "action",
          "event": "filter-risk-all"
        },
        {
          "id": "risk-filter-pending",
          "role": "action",
          "event": "filter-risk-pending"
        },
        {
          "id": "risk-filter-inprogress",
          "role": "action",
          "event": "filter-risk-inprogress"
        },
        {
          "id": "risk-filter-review",
          "role": "action",
          "event": "filter-risk-review"
        },
        {
          "id": "risk-filter-closed",
          "role": "action",
          "event": "filter-risk-closed"
        },
        {
          "id": "risk-add-button",
          "role": "action",
          "event": "navigate-report-risk"
        },
        {
          "id": "risk-search-input",
          "role": "input",
          "binding": "/risks/searchQuery"
        },
        {
          "id": "risk-list",
          "role": "list",
          "binding": "/risks",
          "itemIdPattern": "risk-item-{id}",
          "emptyStateId": "risk-empty-list"
        },
        {
          "id": "risk-item-{id}",
          "role": "action",
          "event": "open-risk-detail",
          "context": { "itemIdPattern": "risk-item-{id}" }
        }
      ]
    },
    {
      "id": "risk-detail-page",
      "surfaceId": "risk-detail",
      "pageId": "risk-detail-page",
      "name": "隐患详情",
      "route": "pages/RiskDetail",
      "semanticTargets": [
        {
          "id": "risk-detail-title",
          "role": "assertion",
          "binding": "/riskDetail/title"
        },
        {
          "id": "risk-detail-status",
          "role": "assertion",
          "binding": "/riskDetail/status"
        },
        {
          "id": "risk-detail-level",
          "role": "assertion",
          "binding": "/riskDetail/level"
        },
        {
          "id": "risk-detail-progress-timeline",
          "role": "list",
          "binding": "/riskDetail/timeline",
          "itemIdPattern": "risk-timeline-{id}",
          "emptyStateId": "risk-empty-timeline"
        },
        {
          "id": "risk-action-assign",
          "role": "action",
          "event": "assign-risk-handler"
        },
        {
          "id": "risk-action-remind",
          "role": "action",
          "event": "remind-risk-handler"
        },
        {
          "id": "risk-action-submit-fix",
          "role": "action",
          "event": "submit-risk-fix"
        },
        {
          "id": "risk-action-review-pass",
          "role": "action",
          "event": "review-risk-pass"
        },
        {
          "id": "risk-action-review-reject",
          "role": "action",
          "event": "review-risk-reject"
        }
      ]
    },
    {
      "id": "report-risk-page",
      "surfaceId": "report-risk",
      "pageId": "report-risk-page",
      "name": "上报隐患",
      "route": "pages/ReportRisk",
      "semanticTargets": [
        {
          "id": "report-risk-title-input",
          "role": "input",
          "binding": "/reportRisk/title"
        },
        {
          "id": "report-risk-type-picker",
          "role": "input",
          "binding": "/reportRisk/type"
        },
        {
          "id": "report-risk-level-picker",
          "role": "input",
          "binding": "/reportRisk/level"
        },
        {
          "id": "report-risk-location-input",
          "role": "input",
          "binding": "/reportRisk/location"
        },
        {
          "id": "report-risk-desc-input",
          "role": "input",
          "binding": "/reportRisk/description"
        },
        {
          "id": "report-risk-photos",
          "role": "input",
          "binding": "/reportRisk/photos"
        },
        {
          "id": "report-risk-deadline-picker",
          "role": "input",
          "binding": "/reportRisk/deadline"
        },
        {
          "id": "report-risk-handler-picker",
          "role": "input",
          "binding": "/reportRisk/handler"
        },
        {
          "id": "report-risk-submit",
          "role": "action",
          "event": "submit-report-risk"
        }
      ]
    },
    {
      "id": "emergency-page",
      "surfaceId": "emergency",
      "pageId": "emergency-page",
      "name": "应急",
      "route": "pages/Emergency",
      "tabId": "tab-emergency",
      "semanticTargets": [
        {
          "id": "emergency-search-input",
          "role": "input",
          "binding": "/emergency/searchQuery"
        },
        {
          "id": "emergency-add-contact",
          "role": "action",
          "event": "open-add-contact-sheet"
        },
        {
          "id": "emergency-contact-list",
          "role": "list",
          "binding": "/emergencyContacts",
          "itemIdPattern": "emergency-contact-{id}",
          "emptyStateId": "emergency-empty-contact"
        },
        {
          "id": "emergency-contact-call-{id}",
          "role": "action",
          "event": "dial-contact",
          "context": { "itemIdPattern": "emergency-contact-{id}" }
        }
      ]
    },
