      "id": "profile-page",
      "surfaceId": "profile",
      "pageId": "profile-page",
      "name": "我的",
      "route": "pages/Profile",
      "tabId": "tab-profile",
      "semanticTargets": [
        {
          "id": "profile-avatar",
          "role": "assertion",
          "binding": "/profile/avatar"
        },
        {
          "id": "profile-name",
          "role": "assertion",
          "binding": "/profile/name"
        },
        {
          "id": "profile-role",
          "role": "assertion",
          "binding": "/profile/role"
        },
        {
          "id": "profile-setting-export",
          "role": "action",
          "event": "export-data"
        },
        {
          "id": "profile-setting-about",
          "role": "action",
          "event": "open-about"
        }
      ]
    }
  ],
  "events": [
    { "name": "navigate-report-risk", "description": "打开隐患上报页" },
    { "name": "navigate-inspection", "description": "切换到巡检 Tab" },
    { "name": "navigate-emergency", "description": "切换到应急 Tab" },
    { "name": "switch-segment-today", "description": "巡检页切换到今日任务" },
    { "name": "switch-segment-pending", "description": "巡检页切换到待办任务" },
    { "name": "switch-segment-history", "description": "巡检页切换到历史记录" },
    { "name": "start-inspection", "description": "开始某条巡检任务" },
    { "name": "open-add-inspection-sheet", "description": "打开新建巡检任务表单" },
    { "name": "mark-checkitem-pass", "description": "巡检项标记为正常" },
    { "name": "mark-checkitem-fail", "description": "巡检项标记为异常并进入隐患池" },
    { "name": "submit-inspection-result", "description": "提交巡检结果" },
    { "name": "filter-risk-all", "description": "隐患筛选全部" },
    { "name": "filter-risk-pending", "description": "隐患筛选待整改" },
    { "name": "filter-risk-inprogress", "description": "隐患筛选整改中" },
    { "name": "filter-risk-review", "description": "隐患筛选待复核" },
    { "name": "filter-risk-closed", "description": "隐患筛选已关闭" },
    { "name": "open-risk-detail", "description": "打开隐患详情" },
    { "name": "assign-risk-handler", "description": "指定/更改整改责任人" },
    { "name": "remind-risk-handler", "description": "催办整改责任人" },
    { "name": "submit-risk-fix", "description": "提交整改结果" },
    { "name": "review-risk-pass", "description": "复核通过并关闭隐患" },
    { "name": "review-risk-reject", "description": "复核不通过并退回整改" },
    { "name": "submit-report-risk", "description": "提交隐患上报表单" },
    { "name": "dial-contact", "description": "拨打应急联系人电话" },
    { "name": "open-add-contact-sheet", "description": "打开新建应急联系人表单" },
    { "name": "export-data", "description": "导出本地数据" },
    { "name": "open-about", "description": "打开关于页面" }
  ],
  "bindings": [
    { "path": "/app/title", "type": "string", "default": "平安扣" },
    { "path": "/stats/todayInspectionCount", "type": "number", "default": 0 },
    { "path": "/stats/pendingRiskCount", "type": "number", "default": 0 },
    { "path": "/stats/overdueRiskCount", "type": "number", "default": 0 },
    { "path": "/stats/closedRate", "type": "string", "default": "0%" },
    { "path": "/charts/riskDistribution", "type": "object" },
    { "path": "/activities", "type": "array" },
    { "path": "/inspectionTasks", "type": "array" },
    { "path": "/inspectionDetail/title", "type": "string" },
    { "path": "/inspectionDetail/checkItems", "type": "array" },
    { "path": "/risks", "type": "array" },
    { "path": "/risks/searchQuery", "type": "string", "default": "" },
    { "path": "/riskDetail/title", "type": "string" },
    { "path": "/riskDetail/status", "type": "string" },
    { "path": "/riskDetail/level", "type": "string" },
    { "path": "/riskDetail/timeline", "type": "array" },
    { "path": "/reportRisk/title", "type": "string" },
    { "path": "/reportRisk/type", "type": "string" },
    { "path": "/reportRisk/level", "type": "string" },
    { "path": "/reportRisk/location", "type": "string" },
    { "path": "/reportRisk/description", "type": "string" },
    { "path": "/reportRisk/photos", "type": "array" },
    { "path": "/reportRisk/deadline", "type": "string" },
    { "path": "/reportRisk/handler", "type": "string" },
    { "path": "/emergency/searchQuery", "type": "string", "default": "" },
    { "path": "/emergencyContacts", "type": "array" },
    { "path": "/profile/avatar", "type": "string" },
    { "path": "/profile/name", "type": "string" },
    { "path": "/profile/role", "type": "string" }
  ],
  "testTargets": [
    "home-stat-today-inspection",
    "home-stat-pending-risk",
    "home-stat-overdue-risk",
    "home-stat-closed-rate",
    "home-quick-action-report",
    "home-quick-action-inspection",
    "home-quick-action-contact",
    "home-recent-activity-list",
    "home-empty-activity",
    "inspection-segment-today",
    "inspection-segment-pending",
    "inspection-segment-history",
    "inspection-task-list",
    "inspection-empty-task",
    "inspection-add-task",
    "inspection-detail-title",
    "inspection-detail-checklist",
    "inspection-submit-result",
    "risk-filter-all",
    "risk-filter-pending",
    "risk-filter-inprogress",
    "risk-filter-review",
    "risk-filter-closed",
    "risk-add-button",
    "risk-search-input",
    "risk-list",
    "risk-empty-list",
    "risk-detail-title",
    "risk-detail-status",
    "risk-detail-level",
    "risk-detail-progress-timeline",
    "risk-action-assign",
    "risk-action-submit-fix",
    "risk-action-review-pass",
    "risk-action-review-reject",
    "report-risk-title-input",
    "report-risk-level-picker",
    "report-risk-submit",
    "emergency-search-input",
    "emergency-add-contact",
    "emergency-contact-list",
    "emergency-empty-contact",
    "profile-name",
    "profile-setting-export",
    "profile-setting-about"
  ]
}

